--- kern_shutdown.c.orig	Tue Feb 17 01:52:07 1998
+++ kern_shutdown.c	Tue Feb 17 01:59:50 1998
@@ -211,6 +211,7 @@
 	if (!cold && (howto & RB_NOSYNC) == 0 && waittime < 0) {
 		register struct buf *bp;
 		int iter, nbusy;
+		int lastnbusy = 0;

 		waittime = 0;
 		printf("\nsyncing disks... ");
@@ -228,6 +229,9 @@
 				break;
 			printf("%d ", nbusy);
 			DELAY(40000 * iter);
+		        if (lastnbusy > nbusy)
+		        	iter = 0;
+		        lastnbusy = nbusy;
 		}
 		if (nbusy) {
 			/*
